text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 배포 목표는 스모크 테스트가 통과되면 금요일 15:00 KST로 한다.",
        "status": "확정"
      },
      {
        "item": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "status": "확정"
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 제안인 smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 바꾸는 안은 채택하지 않는다.",
        "status": "거절"
      },
      {
        "item": "세오연의 수요일 배포 제안은 스모크 테스트 통과 전이라 최종안이 아니다.",
        "status": "거절/미채택"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 배포는 내부 스트레치 목표로만 둔다.",
        "status": "내부 목표"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 절차는 목요일까지 검토하면 좋겠다는 제안이 있었지만, 담당자는 지정되지 않았다.",
        "status": "미결정"
      }
    ],
    "risks": [
      {
        "item": "잘못된 tarball 경로는 배포를 지연시킬 수 있다.",
        "status": "확인된 위험"
      },
      {
        "item": "README 설치 절차가 오래되면 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있다.",
        "status": "확인된 위험"
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한이 누구에게 있는가?",
        "status": "미해결"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할 것인가?",
        "status": "미결정"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "대기 중",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "대기 중",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": null,
      "status": "대기 중",
      "source_certainty": "확정"
    }
  ],
  "followup_note": "다음에는 스모크 테스트 결과와 tarball 경로를 먼저 확인하고, 그다음 README 설치 절차의 최신성을 검토한다. 고객명, 예산, 보안 사고, 운영 중단, 법무 승인 요구사항, 최종 승인 권한은 이 피xture에 없으므로 절대 추정해 넣지 않는다. 내부 수요일 목표는 최종 결론이 아니라 스트레치 목표로만 다룬다.",
  "non_invention_rules": [
    "고객명은 적지 않는다.",
    "예산 정보는 적지 않는다.",
    "보안 사고는 적지 않는다.",
    "운영 중단은 적지 않는다.",
    "법무 승인 요구사항은 적지 않는다.",
    "최종 릴리스 승인자는 단정하지 않는다.",
    "Hara의 정확한 마감 시각은 만들지 않는다.",
    "명시되지 않은 외부 파트너나 이해관계자는 추가하지 않는다.",
    "결정되지 않은 사항은 결정된 것처럼 쓰지 않는다.",
    "스모크 테스트 통과 여부와 tarball 경로는 확인 전까지 확정 사실로 쓰지 않는다."
  ]
}
